+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a","an","the","and","or","but","is","are","was","were","be","been",
+        "being","have","has","had","do","does","did","will","would","could",
+        "should","may","might","shall","can","to","of","in","for","on","with",
+        "at","by","from","as","into","through","during","before","after","it",
+        "its","this","that","these","those","i","you","he","she","we","they",
+        "me","him","her","us","them","my","your","his","our","their","not","no"
+    };
+
+    public string Summarize(string text, int maxSentences = 3)
+    {
+        if (string.IsNullOrWhiteSpace(text))
+            return string.Empty;
+
+        var sentences = SplitSentences(text);
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = BuildWordFrequencies(sentences);
+        var scored = sentences
+            .Select((sentence, index) => (Index: index, Sentence: sentence, Score: ScoreSentence(sentence, wordFrequencies)))
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Sentence);
+
+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in ExtractWords(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+        return freq;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
+    {
+        var words = ExtractWords(sentence);
+        if (words.Count == 0)
+            return 0;
+
+        double score = words
+            .Where(w => !StopWords.Contains(w))
+            .Sum(w => wordFrequencies.GetValueOrDefault(w));
+
+        // Normalize by word count to avoid bias toward long sentences
+        return score / words.Count;
+    }
+
+    private static List<string> ExtractWords(string text)
+    {
+        return WordRegex()
+            .Matches(text)
+            .Select(m => m.Value)
+            .ToList();
+    }
+
+    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
+    private static partial Regex SentenceRegex();
+
+    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
